/**
 * Script storage and quality validation for the moyo psychology channel.
 * Script content is generated by Claude Code directly, not via API calls.
 * This module handles saving, loading, and validating scripts.
 */

const fs = require('fs');
const path = require('path');

const SCRIPTS_DIR = path.join(__dirname, '..', 'data', 'scripts');

/**
 * Validate a script against quality gates.
 * @param {object} script
 * @returns {{ passed: boolean, word_count: number, citation_count: number, issues: string[] }}
 */
function validateScript(script) {
  const issues = [];

  // Count words across all narration
  let totalWords = 0;
  if (script.hook?.text) totalWords += script.hook.text.split(/\s+/).length;
  for (const sec of script.sections || []) {
    if (sec.narration) totalWords += sec.narration.split(/\s+/).length;
  }
  if (script.outro?.narration) totalWords += script.outro.narration.split(/\s+/).length;

  // Count citations
  const citations = script.metadata?.key_studies_referenced || [];
  const citationCount = citations.length;

  // Quality gates
  if (totalWords < 1400) issues.push(`Word count too low: ${totalWords} (min 1400)`);
  if (totalWords > 1800) issues.push(`Word count too high: ${totalWords} (max 1800)`);
  if (citationCount < 5) issues.push(`Too few citations: ${citationCount} (min 5)`);
  if (!script.hook?.text) issues.push('Missing hook');
  if (!script.sections || script.sections.length < 4) issues.push('Too few sections (min 4)');
  if (!script.outro?.narration) issues.push('Missing outro');

  return {
    passed: issues.length === 0,
    word_count: totalWords,
    citation_count: citationCount,
    section_count: (script.sections || []).length,
    issues,
  };
}

/**
 * Save a script to disk.
 * @param {object} script - the script object
 * @param {object} seo - SEO metadata
 * @param {string} topic
 * @param {string} pillarId
 * @returns {string} - file path
 */
function saveScript(script, seo, topic, pillarId) {
  fs.mkdirSync(SCRIPTS_DIR, { recursive: true });

  const slug = topic
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-|-$/g, '')
    .slice(0, 60);
  const filename = `${Date.now()}_${slug}.json`;
  const filePath = path.join(SCRIPTS_DIR, filename);

  const validation = validateScript(script);

  const output = {
    generated_at: new Date().toISOString(),
    topic,
    pillar: pillarId,
    script,
    seo,
    validation,
  };

  fs.writeFileSync(filePath, JSON.stringify(output, null, 2));
  return filePath;
}

/**
 * Load all previously generated topics (for dedup).
 * @returns {string[]}
 */
function loadUsedTopics() {
  if (!fs.existsSync(SCRIPTS_DIR)) return [];

  return fs.readdirSync(SCRIPTS_DIR)
    .filter(f => f.endsWith('.json'))
    .map(f => {
      try {
        const data = JSON.parse(fs.readFileSync(path.join(SCRIPTS_DIR, f), 'utf8'));
        return data.topic;
      } catch {
        return null;
      }
    })
    .filter(Boolean);
}

module.exports = { validateScript, saveScript, loadUsedTopics, SCRIPTS_DIR };
